// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope;

import static org.assertj.core.api.Assertions.assertThat;

import java.lang.reflect.Method;
import java.util.LinkedHashSet;
import java.util.Set;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

public class ScopeRewriteGuardTest {

	@Test
	public void selectsOneFinalGuardForEachMaskLayout() throws Exception {
		assertThat(createGuard(analysisWithSymbols(64)).getClass().getSimpleName()).isEqualTo("ScopeRewriteGuard64");
		assertThat(createGuard(analysisWithSymbols(65)).getClass().getSimpleName()).isEqualTo("ScopeRewriteGuard128");
		assertThat(createGuard(analysisWithSymbols(129)).getClass().getSimpleName()).isEqualTo("ScopeRewriteGuardWide");
	}

	@Test
	public void filterMovementAndJoinSwapsRespectDirectionalInputs() throws Exception {
		StatementPattern left = pattern("left", "leftOnly");
		StatementPattern right = pattern("right", "rightOnly");
		Join safeJoin = new Join(left, right);
		Filter safeFilter = new Filter(safeJoin, Var.of("leftOnly"));
		ScopeAnalysis safeAnalysis = ScopeAnalysis.analyze(new QueryRoot(safeFilter));
		Object safeGuard = createGuard(safeAnalysis);
		assertThat(filterBelowJoin(safeGuard, safeFilter, left, right)).isZero();

		StatementPattern deniedLeft = pattern("left", "leftOnly");
		StatementPattern deniedRight = pattern("right", "rightOnly");
		Join deniedJoin = new Join(deniedLeft, deniedRight);
		Filter deniedFilter = new Filter(deniedJoin, Var.of("rightOnly"));
		ScopeAnalysis deniedAnalysis = ScopeAnalysis.analyze(new QueryRoot(deniedFilter));
		Object deniedGuard = createGuard(deniedAnalysis);
		assertThat(filterBelowJoin(deniedGuard, deniedFilter, deniedLeft, deniedRight)).isPositive();

		StatementPattern provider = pattern("left", "provided");
		Filter dependent = new Filter(pattern("right", "rightOnly"), Var.of("provided"));
		Join directional = new Join(provider, dependent);
		ScopeAnalysis directionalAnalysis = ScopeAnalysis.analyze(new QueryRoot(directional));
		Object directionalGuard = createGuard(directionalAnalysis);
		assertThat(canSwapJoin(directionalGuard, provider, dependent)).isPositive();
	}

	private static ScopeAnalysis analysisWithSymbols(int count) {
		Set<String> names = new LinkedHashSet<>();
		for (int i = 0; i < count; i++) {
			names.add("v" + i);
		}
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setDeclaredBindingNames(names);
		return ScopeAnalysis.analyze(new QueryRoot(assignment));
	}

	private static StatementPattern pattern(String first, String second) {
		return new StatementPattern(Var.of(first),
				Var.of("_p", SimpleValueFactory.getInstance().createIRI("urn:p")), Var.of(second));
	}

	private static Object createGuard(ScopeAnalysis analysis) throws Exception {
		Class<?> type = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope.ScopeRewriteGuard");
		Method create = type.getDeclaredMethod("create", ScopeAnalysis.class);
		create.setAccessible(true);
		return create.invoke(null, analysis);
	}

	private static int filterBelowJoin(Object guard, Filter filter, TupleExpr destination, TupleExpr crossed)
			throws Exception {
		Method method = guard.getClass()
				.getDeclaredMethod("filterBelowJoin", Filter.class, TupleExpr.class,
						TupleExpr.class);
		method.setAccessible(true);
		return (int) method.invoke(guard, filter, destination, crossed);
	}

	private static int canSwapJoin(Object guard, TupleExpr left, TupleExpr right) throws Exception {
		Method method = guard.getClass().getDeclaredMethod("canSwapJoin", TupleExpr.class, TupleExpr.class);
		method.setAccessible(true);
		return (int) method.invoke(guard, left, right);
	}
}
